import Phaser from "phaser";
import type { EngineVoice } from "./EngineVoice";
import { AudioKeys } from "./AudioKeys";

const MIN_RATE = 0.6;
const MAX_RATE = 1.8;
const MIN_VOLUME = 0.3;
const MAX_VOLUME = 0.9;

/**
 * Plays a looped engine sample and modulates playback rate + volume by speed
 * ratio. Activated automatically when `AudioKeys.EngineLoop` is in the audio
 * cache (load it from BootScene once you have a sample).
 */
export class SampledEngineVoice implements EngineVoice {
  private readonly engineSound: Phaser.Sound.BaseSound &
    Phaser.Sound.WebAudioSound;
  private readonly scene: Phaser.Scene;

  constructor(scene: Phaser.Scene) {
    this.scene = scene;
    this.engineSound = scene.sound.add(AudioKeys.EngineLoop, {
      loop: true,
      volume: MIN_VOLUME,
      rate: MIN_RATE,
    }) as Phaser.Sound.BaseSound & Phaser.Sound.WebAudioSound;
    this.engineSound.play();
  }

  setSpeed(ratio: number): void {
    const r = Phaser.Math.Clamp(ratio, 0, 1);
    this.engineSound.setRate(Phaser.Math.Linear(MIN_RATE, MAX_RATE, r));
    this.engineSound.setVolume(Phaser.Math.Linear(MIN_VOLUME, MAX_VOLUME, r));
  }

  triggerBackfire(): void {
    if (this.scene.cache.audio.exists(AudioKeys.Backfire)) {
      this.scene.sound.play(AudioKeys.Backfire, { volume: 0.6 });
    }
  }

  destroy(): void {
    this.engineSound.stop();
    this.engineSound.destroy();
  }
}
