import Phaser from "phaser";
import { SceneKeys, TextureKeys } from "@/games/overtake/config/constants";
import { CAR_HEIGHT, CAR_WIDTH } from "@/games/overtake/config/cars";

export class BootScene extends Phaser.Scene {
  constructor() {
    super(SceneKeys.Boot);
  }

  preload(): void {
    this.generateCarTexture(TextureKeys.CarRed, 0xe53935);
    this.generateCarTexture(TextureKeys.CarBlue, 0x1e88e5);
    this.generateCarTexture(TextureKeys.CarYellow, 0xfdd835);
    this.generateCarTexture(TextureKeys.TrafficGreen, 0x43a047);
    this.generateCarTexture(TextureKeys.TrafficWhite, 0xeceff1);
    this.generateCarTexture(TextureKeys.TrafficOrange, 0xfb8c00);
    this.generateRoadStripe();

    // To switch SoundManager from synth fallback to the sampled backend:
    //   1. Drop audio files in `public/audio/` (engine.ogg, backfire.ogg, ...)
    //   2. Add `import { AudioKeys } from "@/games/overtake/config/constants";` above
    //   3. Uncomment the four loader calls below
    //
    // this.load.audio(AudioKeys.EngineLoop, ["audio/engine.ogg", "audio/engine.mp3"]);
    // this.load.audio(AudioKeys.Backfire, ["audio/backfire.ogg", "audio/backfire.mp3"]);
    // this.load.audio(AudioKeys.GearShift, ["audio/gear.ogg", "audio/gear.mp3"]);
    // this.load.audio(AudioKeys.Crash, ["audio/crash.ogg", "audio/crash.mp3"]);
  }

  create(): void {
    this.scene.start(SceneKeys.Menu);
  }

  private generateCarTexture(key: string, color: number): void {
    if (this.textures.exists(key)) return;
    const g = this.add.graphics();
    g.fillStyle(0x111111, 1);
    g.fillRoundedRect(0, 0, CAR_WIDTH, CAR_HEIGHT, 8);
    g.fillStyle(color, 1);
    g.fillRoundedRect(4, 6, CAR_WIDTH - 8, CAR_HEIGHT - 12, 6);
    g.fillStyle(0x0d0d0d, 1);
    g.fillRect(10, 18, CAR_WIDTH - 20, 18);
    g.fillRect(10, CAR_HEIGHT - 36, CAR_WIDTH - 20, 18);
    g.fillStyle(0xffeb3b, 1);
    g.fillRect(6, 2, 8, 4);
    g.fillRect(CAR_WIDTH - 14, 2, 8, 4);
    g.generateTexture(key, CAR_WIDTH, CAR_HEIGHT);
    g.destroy();
  }

  private generateRoadStripe(): void {
    if (this.textures.exists(TextureKeys.RoadStripe)) return;
    const g = this.add.graphics();
    g.fillStyle(0xffffff, 1);
    g.fillRect(0, 0, 6, 40);
    g.generateTexture(TextureKeys.RoadStripe, 6, 40);
    g.destroy();
  }
}
