import Phaser from "phaser";
import { GAME_HEIGHT } from "@/games/overtake/config/constants";
import { CarChoice } from "@/games/overtake/config/cars";
import { LANE_COUNT, laneIndexToX } from "@/games/overtake/config/lanes";

const LANE_CHANGE_DURATION = 180;

export class PlayerCar {
  readonly sprite: Phaser.Physics.Arcade.Sprite;
  private laneIndex: number;
  private targetX: number;
  private isChanging = false;

  constructor(scene: Phaser.Scene, choice: CarChoice) {
    this.laneIndex = Math.max(0, Math.floor(LANE_COUNT / 2) - 1);
    this.targetX = laneIndexToX(this.laneIndex);
    this.sprite = scene.physics.add.sprite(
      this.targetX,
      GAME_HEIGHT - 140,
      choice.textureKey,
    );
    this.sprite.setCollideWorldBounds(true);
    this.sprite.setImmovable(true);
    this.sprite.body!.setSize(this.sprite.width * 0.8, this.sprite.height * 0.85);
  }

  changeLane(direction: -1 | 1): void {
    if (this.isChanging) return;
    const next = this.laneIndex + direction;
    if (next < 0 || next >= LANE_COUNT) return;
    this.laneIndex = next;
    this.targetX = laneIndexToX(this.laneIndex);
    this.isChanging = true;
    this.sprite.scene.tweens.add({
      targets: this.sprite,
      x: this.targetX,
      duration: LANE_CHANGE_DURATION,
      ease: "Cubic.easeOut",
      onComplete: () => {
        this.isChanging = false;
      },
    });
  }

  update(_dt: number): void {
    // Lane locked; vertical position is fixed. Speed is conveyed via road scroll.
  }

  get currentLane(): number {
    return this.laneIndex;
  }
}
