import Phaser from "phaser";
import { laneIndexToX } from "@/games/overtake/config/lanes";

let nextId = 1;

export class TrafficCar {
  readonly id: number;
  readonly sprite: Phaser.Physics.Arcade.Sprite;
  readonly lane: number;
  readonly worldSpeed: number;

  constructor(
    scene: Phaser.Scene,
    group: Phaser.Physics.Arcade.Group,
    lane: number,
    textureKey: string,
    worldSpeed: number,
    spawnY: number,
  ) {
    this.id = nextId++;
    this.lane = lane;
    this.worldSpeed = worldSpeed;
    this.sprite = scene.physics.add.sprite(laneIndexToX(lane), spawnY, textureKey);
    this.sprite.setData("ref", this);
    this.sprite.setImmovable(true);
    this.sprite.body!.setSize(
      this.sprite.width * 0.8,
      this.sprite.height * 0.85,
    );
    group.add(this.sprite);
  }

  update(dt: number, playerSpeed: number): void {
    const relative = playerSpeed - this.worldSpeed;
    this.sprite.y += relative * dt;
  }

  destroy(): void {
    this.sprite.destroy();
  }
}
