import Phaser from "phaser";
import { EventKeys, GAME_HEIGHT, GAME_WIDTH, SceneKeys } from "@/games/overtake/config/constants";
import { MAX_SPEED } from "@/games/overtake/config/gears";

export class HudScene extends Phaser.Scene {
  private gearText!: Phaser.GameObjects.Text;
  private speedText!: Phaser.GameObjects.Text;
  private scoreText!: Phaser.GameObjects.Text;
  private turboBadge!: Phaser.GameObjects.Text;
  private speedBar!: Phaser.GameObjects.Graphics;

  constructor() {
    super(SceneKeys.Hud);
  }

  create(): void {
    const gameScene = this.scene.get(SceneKeys.Game);

    const panel = this.add.rectangle(0, 0, GAME_WIDTH, 60, 0x000000, 0.55);
    panel.setOrigin(0, 0);

    this.gearText = this.add
      .text(20, 30, "VİTES\n1", {
        fontFamily: "system-ui, sans-serif",
        fontSize: "16px",
        color: "#ffeb3b",
        align: "center",
        fontStyle: "bold",
      })
      .setOrigin(0, 0.5);

    this.speedText = this.add
      .text(GAME_WIDTH / 2, 30, "0 km/s", {
        fontFamily: "system-ui, sans-serif",
        fontSize: "22px",
        color: "#ffffff",
        fontStyle: "bold",
      })
      .setOrigin(0.5, 0.5);

    this.scoreText = this.add
      .text(GAME_WIDTH - 20, 30, "0", {
        fontFamily: "system-ui, sans-serif",
        fontSize: "20px",
        color: "#a5d6a7",
        fontStyle: "bold",
      })
      .setOrigin(1, 0.5);

    this.turboBadge = this.add
      .text(GAME_WIDTH / 2, 70, "TURBO  x2 PUAN", {
        fontFamily: "system-ui, sans-serif",
        fontSize: "14px",
        color: "#ff5252",
        fontStyle: "bold",
        backgroundColor: "#1a1a1a",
        padding: { x: 10, y: 4 },
      })
      .setOrigin(0.5, 0.5)
      .setVisible(false);

    this.speedBar = this.add.graphics();
    this.drawSpeedBar(0);

    gameScene.events.on(EventKeys.GearChanged, (gear: string) => {
      this.gearText.setText(`VİTES\n${gear}`);
    });
    gameScene.events.on(EventKeys.SpeedChanged, (speed: number) => {
      this.speedText.setText(`${Math.round(speed)} km/s`);
      this.drawSpeedBar(speed);
    });
    gameScene.events.on(EventKeys.ScoreChanged, (score: number) => {
      this.scoreText.setText(`${score}`);
    });
    gameScene.events.on(EventKeys.MultiplierChanged, (mult: number) => {
      this.setTurbo(mult > 1);
    });

    this.events.once(Phaser.Scenes.Events.SHUTDOWN, () => {
      gameScene.events.off(EventKeys.GearChanged);
      gameScene.events.off(EventKeys.SpeedChanged);
      gameScene.events.off(EventKeys.ScoreChanged);
      gameScene.events.off(EventKeys.MultiplierChanged);
    });
  }

  private setTurbo(active: boolean): void {
    if (active === this.turboBadge.visible) return;
    this.turboBadge.setVisible(active);
    if (active) {
      this.tweens.add({
        targets: this.turboBadge,
        scale: { from: 1.4, to: 1 },
        duration: 250,
        ease: "Back.easeOut",
      });
    }
  }

  private drawSpeedBar(speed: number): void {
    const barX = 20;
    const barY = GAME_HEIGHT - 28;
    const barW = GAME_WIDTH - 40;
    const barH = 10;
    const ratio = Phaser.Math.Clamp(speed / MAX_SPEED, 0, 1);

    this.speedBar.clear();
    this.speedBar.fillStyle(0x222222, 0.8);
    this.speedBar.fillRoundedRect(barX, barY, barW, barH, 4);
    this.speedBar.fillStyle(this.colorForRatio(ratio), 1);
    this.speedBar.fillRoundedRect(barX, barY, barW * ratio, barH, 4);
  }

  private colorForRatio(r: number): number {
    if (r < 0.4) return 0x4caf50;
    if (r < 0.75) return 0xfdd835;
    return 0xe53935;
  }
}
