import { GAME_WIDTH } from "./constants";

export const LANE_COUNT = 4;
export const LANE_WIDTH = GAME_WIDTH / LANE_COUNT;

export const LANE_CENTERS: readonly number[] = Array.from(
  { length: LANE_COUNT },
  (_, i) => LANE_WIDTH * i + LANE_WIDTH / 2,
);

export function laneIndexToX(index: number): number {
  const clamped = Math.max(0, Math.min(LANE_COUNT - 1, index));
  return LANE_CENTERS[clamped];
}
