const LEGACY_KEY = "makas:highscore";

function storageKey(gameId: string, slot: string): string {
  return `game:${gameId}:highscore:${slot}`;
}

function migrateLegacy(gameId: string, slot: string): void {
  if (gameId !== "overtake" || slot !== "default") return;
  try {
    const newKey = storageKey(gameId, slot);
    if (window.localStorage.getItem(newKey) !== null) return;
    const legacy = window.localStorage.getItem(LEGACY_KEY);
    if (legacy === null) return;
    window.localStorage.setItem(newKey, legacy);
    window.localStorage.removeItem(LEGACY_KEY);
  } catch {
    /* ignore */
  }
}

export const HighScore = {
  load(gameId: string, slot = "default"): number {
    migrateLegacy(gameId, slot);
    try {
      const raw = window.localStorage.getItem(storageKey(gameId, slot));
      if (!raw) return 0;
      const parsed = parseInt(raw, 10);
      return Number.isFinite(parsed) && parsed >= 0 ? parsed : 0;
    } catch {
      return 0;
    }
  },

  save(gameId: string, score: number, slot = "default"): boolean {
    try {
      const current = this.load(gameId, slot);
      if (score <= current) return false;
      window.localStorage.setItem(storageKey(gameId, slot), String(score));
      return true;
    } catch {
      return false;
    }
  },
};
