import Phaser from "phaser";
import { CarChoice } from "@/games/overtake/config/cars";
import { BRAKE_DECEL, COAST_DECEL, GEARS, GearProfile } from "@/games/overtake/config/gears";
import { EventKeys } from "@/games/overtake/config/constants";

export class GearSystem {
  private readonly scene: Phaser.Scene;
  private readonly choice: CarChoice;
  private gearIndex = 0;
  private _speed = 0;

  constructor(scene: Phaser.Scene, choice: CarChoice) {
    this.scene = scene;
    this.choice = choice;
  }

  reset(): void {
    this.start(0, 0);
  }

  start(initialSpeed: number, initialGearIndex: number): void {
    this.gearIndex = Phaser.Math.Clamp(initialGearIndex, 0, GEARS.length - 1);
    const profile = this.currentProfile;
    const topSpeed = profile.maxSpeed + this.choice.topSpeedBonus;
    this._speed = Phaser.Math.Clamp(initialSpeed, 0, topSpeed);
    this.emitGear();
    this.emitSpeed();
  }

  shiftUp(): void {
    if (this.gearIndex < GEARS.length - 1) {
      this.gearIndex++;
      this.emitGear();
    }
  }

  shiftDown(): void {
    if (this.gearIndex > 0) {
      this.gearIndex--;
      this.emitGear();
    }
  }

  update(dt: number, accel: boolean, brake: boolean): void {
    const profile = this.currentProfile;
    const topSpeed = this.isTopGear ? Infinity : (profile.maxSpeed + this.choice.topSpeedBonus);
    const accelRate = profile.accel + this.choice.accelBonus;

    if (brake) {
      this._speed = Math.max(0, this._speed - BRAKE_DECEL * dt);
    } else if (accel) {
      this._speed = Math.min(topSpeed, this._speed + accelRate * dt);
    } else {
      this._speed = Math.max(0, this._speed - COAST_DECEL * dt);
    }

    if (this._speed < profile.minSpeed * 0.6 && this.gearIndex > 0) {
      // Engine struggles in too-high gear: slowly bleed speed.
      this._speed = Math.max(0, this._speed - 20 * dt);
    }

    this.emitSpeed();
  }

  get speed(): number {
    return this._speed;
  }

  get currentProfile(): GearProfile {
    return GEARS[this.gearIndex];
  }

  get currentGearIndex(): number {
    return this.gearIndex;
  }

  get isTopGear(): boolean {
    return this.gearIndex === GEARS.length - 1;
  }

  get gearLabel(): string {
    return this.currentProfile.label;
  }

  private emitGear(): void {
    this.scene.events.emit(EventKeys.GearChanged, this.gearLabel);
    this.scene.events.emit(EventKeys.MultiplierChanged, this.isTopGear ? 2 : 1);
  }

  private emitSpeed(): void {
    this.scene.events.emit(EventKeys.SpeedChanged, this._speed);
  }
}
