import Phaser from "phaser";
import { GAME_HEIGHT, GAME_WIDTH, SceneKeys } from "@/games/overtake/config/constants";
import { CAR_CHOICES } from "@/games/overtake/config/cars";
import { Road } from "@/games/overtake/entities/Road";

interface IntroData {
  readonly choiceId: string;
}

export class IntroScene extends Phaser.Scene {
  private road!: Road;

  constructor() {
    super(SceneKeys.Intro);
  }

  create(data: IntroData): void {
    const choice = CAR_CHOICES.find((c) => c.id === data.choiceId) ?? CAR_CHOICES[0];
    this.road = new Road(this);

    const car = this.add.image(GAME_WIDTH / 2, GAME_HEIGHT + 80, choice.textureKey);

    this.tweens.add({
      targets: car,
      y: GAME_HEIGHT - 160,
      duration: 1400,
      ease: "Cubic.easeOut",
    });

    this.tweens.add({
      targets: this.road,
      scrollSpeed: 480,
      duration: 1600,
      delay: 200,
      ease: "Cubic.easeOut",
      onComplete: () => {
        this.scene.start(SceneKeys.Countdown, { choiceId: choice.id });
      },
    });

    this.add
      .text(GAME_WIDTH / 2, 60, "HAZIRLAN", {
        fontFamily: "system-ui, sans-serif",
        fontSize: "32px",
        color: "#ffeb3b",
        fontStyle: "bold",
      })
      .setOrigin(0.5);
  }

  override update(_time: number, delta: number): void {
    this.road.update(delta);
  }
}
