import Phaser from "phaser";
import { TextureKeys } from "@/games/parking/config/constants";
import {
  ACCEL_FORWARD,
  ACCEL_REVERSE,
  BRAKE_DECEL,
  COAST_DECEL,
  MAX_FORWARD_SPEED,
  MAX_REVERSE_SPEED,
  PARK_DECEL,
  STEER_RATE,
} from "@/games/parking/config/gears";
import { CAR_HEIGHT, CAR_WIDTH, type SlotPos } from "@/games/parking/config/lot";

/**
 * Free 2D player with bicycle-style steering: only turns while moving.
 * Speed is signed (positive = forward, negative = reverse). The arcade
 * collision body is a circle so rotated visuals don't cause weird AABB
 * snags against parked cars — the soft-bump feel matches the game spec.
 */
export class ParkingCar {
  readonly sprite: Phaser.Physics.Arcade.Sprite;
  /** Signed speed. Positive = nose-forward, negative = reversing. */
  speed = 0;

  constructor(scene: Phaser.Scene, start: SlotPos) {
    this.sprite = scene.physics.add.sprite(start.x, start.y, TextureKeys.PlayerCar);
    this.sprite.setRotation(Phaser.Math.DegToRad(start.angle));
    const body = this.sprite.body as Phaser.Physics.Arcade.Body;
    body.setCircle(CAR_WIDTH / 2);
    body.setOffset(
      0,
      CAR_HEIGHT / 2 - CAR_WIDTH / 2,
    );
    body.setBounce(0.2, 0.2);
    body.setDamping(true);
    body.setDrag(0.7, 0.7);
    body.setMaxVelocity(220);
    this.sprite.setCollideWorldBounds(true);
  }

  /** Hard stop and snap velocity to zero (used when player engages P). */
  forceStop(): void {
    this.speed = 0;
    (this.sprite.body as Phaser.Physics.Arcade.Body).setVelocity(0, 0);
  }

  /**
   * @param thrustSign  -1 reverse, +1 forward, 0 none
   * @param brake       0..1 brake input
   * @param steer       -1..1 steering input
   * @param parking     true while in P; force a hard decel
   */
  update(
    dt: number,
    thrustSign: -1 | 0 | 1,
    brake: number,
    steer: number,
    parking: boolean,
  ): void {
    if (parking) {
      this.speed = this.bleedToZero(this.speed, PARK_DECEL * dt);
    } else if (brake > 0) {
      this.speed = this.bleedToZero(this.speed, BRAKE_DECEL * dt);
    } else if (thrustSign === 1) {
      this.speed = Math.min(MAX_FORWARD_SPEED, this.speed + ACCEL_FORWARD * dt);
    } else if (thrustSign === -1) {
      this.speed = Math.max(-MAX_REVERSE_SPEED, this.speed - ACCEL_REVERSE * dt);
    } else {
      this.speed = this.bleedToZero(this.speed, COAST_DECEL * dt);
    }

    if (Math.abs(this.speed) > 1) {
      const speedRatio = this.speed / MAX_FORWARD_SPEED;
      this.sprite.rotation += steer * STEER_RATE * speedRatio * dt;
    }

    const heading = this.sprite.rotation;
    const vx = Math.sin(heading) * this.speed;
    const vy = -Math.cos(heading) * this.speed;
    (this.sprite.body as Phaser.Physics.Arcade.Body).setVelocity(vx, vy);
  }

  get position(): { x: number; y: number } {
    return { x: this.sprite.x, y: this.sprite.y };
  }

  get angleDeg(): number {
    return Phaser.Math.RadToDeg(this.sprite.rotation);
  }

  private bleedToZero(value: number, amount: number): number {
    if (value > 0) return Math.max(0, value - amount);
    if (value < 0) return Math.min(0, value + amount);
    return 0;
  }
}
