import type { EngineVoice } from "./EngineVoice";

interface EngineNodes {
  oscillators: OscillatorNode[];
  saws: [OscillatorNode, OscillatorNode];
  sub: OscillatorNode;
  noise: AudioBufferSourceNode;
  noiseFilter: BiquadFilterNode;
  masterGain: GainNode;
  filter: BiquadFilterNode;
}

/**
 * Layered Web Audio engine: two detuned saws (cylinders) + sub triangle
 * (block) + filtered noise (exhaust) routed through a soft waveshaper and
 * a speed-driven lowpass. Vibrato + amplitude LFOs add the rough-motor
 * wobble pure sawtooth alone can't deliver.
 */
export class SynthEngineVoice implements EngineVoice {
  private readonly ctx: AudioContext;
  private readonly engine: EngineNodes;

  constructor(ctx: AudioContext) {
    this.ctx = ctx;
    this.engine = this.start();
  }

  setSpeed(ratio: number): void {
    const fundamental = 50 + ratio * 130;
    const cutoff = 360 + ratio * 1900;
    const targetGain = 0.05 + ratio * 0.09;
    const noiseCutoff = 220 + ratio * 700;

    const now = this.ctx.currentTime;
    this.engine.saws[0].frequency.setTargetAtTime(fundamental, now, 0.1);
    this.engine.saws[1].frequency.setTargetAtTime(fundamental, now, 0.1);
    this.engine.sub.frequency.setTargetAtTime(fundamental * 0.5, now, 0.1);
    this.engine.filter.frequency.setTargetAtTime(cutoff, now, 0.15);
    this.engine.masterGain.gain.setTargetAtTime(targetGain, now, 0.15);
    this.engine.noiseFilter.frequency.setTargetAtTime(noiseCutoff, now, 0.15);
  }

  triggerBackfire(): void {
    const ctx = this.ctx;
    const buffer = ctx.createBuffer(1, ctx.sampleRate * 0.22, ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < data.length; i++) {
      const env = Math.exp(-i / (ctx.sampleRate * 0.06));
      data[i] = (Math.random() * 2 - 1) * env;
    }
    const src = ctx.createBufferSource();
    src.buffer = buffer;
    const filter = ctx.createBiquadFilter();
    filter.type = "lowpass";
    filter.frequency.value = 480;
    const gain = ctx.createGain();
    gain.gain.value = 0.4;
    src.connect(filter).connect(gain).connect(ctx.destination);
    src.start();
  }

  destroy(): void {
    for (const o of this.engine.oscillators) {
      try {
        o.stop();
      } catch {
        /* noop */
      }
      o.disconnect();
    }
    try {
      this.engine.noise.stop();
    } catch {
      /* noop */
    }
    this.engine.noise.disconnect();
    this.engine.masterGain.disconnect();
    this.engine.filter.disconnect();
    this.engine.noiseFilter.disconnect();
  }

  private start(): EngineNodes {
    const ctx = this.ctx;
    const filter = ctx.createBiquadFilter();
    filter.type = "lowpass";
    filter.frequency.value = 380;
    filter.Q.value = 0.8;

    const shaper = ctx.createWaveShaper();
    shaper.curve = this.makeDistortionCurve(18);
    shaper.oversample = "2x";

    const masterGain = ctx.createGain();
    masterGain.gain.value = 0.0;

    const saw1 = ctx.createOscillator();
    saw1.type = "sawtooth";
    saw1.frequency.value = 55;
    saw1.detune.value = -7;
    const saw2 = ctx.createOscillator();
    saw2.type = "sawtooth";
    saw2.frequency.value = 55;
    saw2.detune.value = 7;

    const sub = ctx.createOscillator();
    sub.type = "triangle";
    sub.frequency.value = 27;

    const sawMix = ctx.createGain();
    sawMix.gain.value = 0.45;
    saw1.connect(sawMix);
    saw2.connect(sawMix);

    const subMix = ctx.createGain();
    subMix.gain.value = 0.55;
    sub.connect(subMix);

    const noiseLen = Math.floor(ctx.sampleRate * 2);
    const noiseBuf = ctx.createBuffer(1, noiseLen, ctx.sampleRate);
    const nd = noiseBuf.getChannelData(0);
    for (let i = 0; i < noiseLen; i++) nd[i] = Math.random() * 2 - 1;
    const noise = ctx.createBufferSource();
    noise.buffer = noiseBuf;
    noise.loop = true;
    const noiseFilter = ctx.createBiquadFilter();
    noiseFilter.type = "bandpass";
    noiseFilter.frequency.value = 220;
    noiseFilter.Q.value = 1.6;
    const noiseMix = ctx.createGain();
    noiseMix.gain.value = 0.18;
    noise.connect(noiseFilter).connect(noiseMix);

    sawMix.connect(shaper);
    subMix.connect(shaper);
    noiseMix.connect(shaper);
    shaper.connect(filter).connect(masterGain).connect(ctx.destination);

    const vibratoLfo = ctx.createOscillator();
    vibratoLfo.frequency.value = 6.5;
    const vibratoGain = ctx.createGain();
    vibratoGain.gain.value = 1.2;
    vibratoLfo.connect(vibratoGain);
    vibratoGain.connect(saw1.frequency);
    vibratoGain.connect(saw2.frequency);
    vibratoGain.connect(sub.frequency);

    const ampLfo = ctx.createOscillator();
    ampLfo.frequency.value = 3.5;
    const ampLfoGain = ctx.createGain();
    ampLfoGain.gain.value = 0.05;
    ampLfo.connect(ampLfoGain);
    ampLfoGain.connect(masterGain.gain);

    saw1.start();
    saw2.start();
    sub.start();
    noise.start();
    vibratoLfo.start();
    ampLfo.start();

    return {
      oscillators: [saw1, saw2, sub, vibratoLfo, ampLfo],
      saws: [saw1, saw2],
      sub,
      noise,
      noiseFilter,
      masterGain,
      filter,
    };
  }

  private makeDistortionCurve(amount: number): Float32Array<ArrayBuffer> {
    const samples = 1024;
    const buf = new ArrayBuffer(samples * Float32Array.BYTES_PER_ELEMENT);
    const curve = new Float32Array(buf);
    const k = amount;
    const deg = Math.PI / 180;
    for (let i = 0; i < samples; i++) {
      const x = (i * 2) / samples - 1;
      curve[i] = ((3 + k) * x * 20 * deg) / (Math.PI + k * Math.abs(x));
    }
    return curve;
  }
}
