import Phaser from "phaser";
import { GAME_HEIGHT, GAME_WIDTH } from "@/shared/constants";
import { HighScore } from "@/shared/storage/HighScore";
import { gameRegistry, type GameDefinition } from "./gameRegistry";

export const HUB_SCENE_KEY = "hub:HubScene";

interface CardRefs {
  container: Phaser.GameObjects.Container;
  bg: Phaser.GameObjects.Rectangle;
  iconBg: Phaser.GameObjects.Rectangle;
  best: Phaser.GameObjects.Text;
}

const CARD_W = 180;
const CARD_H = 280;
const CARD_GAP = 20;

export class HubScene extends Phaser.Scene {
  private games: readonly GameDefinition[] = gameRegistry;
  private cards: CardRefs[] = [];
  private selected = 0;

  constructor() {
    super(HUB_SCENE_KEY);
  }

  create(): void {
    this.cards = [];
    this.selected = this.firstEnabledIndex();

    this.add
      .text(GAME_WIDTH / 2, 80, "MAKAS GARAGE", {
        fontFamily: "system-ui, sans-serif",
        fontSize: "40px",
        color: "#ffeb3b",
        fontStyle: "bold",
      })
      .setOrigin(0.5);

    this.add
      .text(GAME_WIDTH / 2, 130, "Bir oyun seç", {
        fontFamily: "system-ui, sans-serif",
        fontSize: "18px",
        color: "#bdbdbd",
      })
      .setOrigin(0.5);

    const totalCardsWidth =
      CARD_W * this.games.length + CARD_GAP * (this.games.length - 1);
    const startX = (GAME_WIDTH - totalCardsWidth) / 2 + CARD_W / 2;
    this.games.forEach((g, i) => {
      const x = startX + i * (CARD_W + CARD_GAP);
      const y = GAME_HEIGHT / 2 + 20;
      this.cards.push(this.buildCard(g, i, x, y));
    });

    this.add
      .text(
        GAME_WIDTH / 2,
        GAME_HEIGHT - 50,
        "← →  seç    ENTER  başla",
        {
          fontFamily: "system-ui, sans-serif",
          fontSize: "14px",
          color: "#9e9e9e",
        },
      )
      .setOrigin(0.5);

    this.input.keyboard?.on("keydown-LEFT", () => this.move(-1));
    this.input.keyboard?.on("keydown-RIGHT", () => this.move(1));
    this.input.keyboard?.on("keydown-ENTER", () => this.confirm());
    this.input.keyboard?.on("keydown-SPACE", () => this.confirm());

    this.refresh();
  }

  private buildCard(
    g: GameDefinition,
    index: number,
    x: number,
    y: number,
  ): CardRefs {
    const container = this.add.container(x, y);
    const bg = this.add.rectangle(0, 0, CARD_W, CARD_H, 0x1f1f1f, 1);
    bg.setStrokeStyle(2, 0x333333);

    const iconBg = this.add.rectangle(
      0,
      -70,
      CARD_W - 40,
      120,
      g.id === "parking" ? 0x1976d2 : 0xc62828,
      1,
    );
    iconBg.setStrokeStyle(2, 0x000000);

    const label = this.add
      .text(0, 30, g.label, {
        fontFamily: "system-ui, sans-serif",
        fontSize: "26px",
        color: "#ffffff",
        fontStyle: "bold",
      })
      .setOrigin(0.5);

    const tagline = this.add
      .text(0, 65, g.tagline, {
        fontFamily: "system-ui, sans-serif",
        fontSize: "13px",
        color: "#bdbdbd",
        align: "center",
        wordWrap: { width: CARD_W - 30 },
      })
      .setOrigin(0.5);

    const best = HighScore.load(g.id);
    const bestText = this.add
      .text(0, 110, best > 0 ? `Rekor: ${best}` : "", {
        fontFamily: "system-ui, sans-serif",
        fontSize: "12px",
        color: "#a5d6a7",
      })
      .setOrigin(0.5);

    if (!g.enabled) {
      const lock = this.add
        .text(0, -70, "YAKINDA", {
          fontFamily: "system-ui, sans-serif",
          fontSize: "16px",
          color: "#ffffff",
          fontStyle: "bold",
          stroke: "#000",
          strokeThickness: 3,
        })
        .setOrigin(0.5);
      container.add([bg, iconBg, label, tagline, bestText, lock]);
      bg.setAlpha(0.55);
      iconBg.setAlpha(0.4);
    } else {
      container.add([bg, iconBg, label, tagline, bestText]);
    }

    container.setSize(CARD_W, CARD_H);
    container.setInteractive(
      new Phaser.Geom.Rectangle(-CARD_W / 2, -CARD_H / 2, CARD_W, CARD_H),
      Phaser.Geom.Rectangle.Contains,
    );
    container.on("pointerover", () => {
      this.selected = index;
      this.refresh();
    });
    container.on("pointerdown", () => {
      this.selected = index;
      this.refresh();
      this.confirm();
    });

    return { container, bg, iconBg, best: bestText };
  }

  private firstEnabledIndex(): number {
    const i = this.games.findIndex((g) => g.enabled);
    return i >= 0 ? i : 0;
  }

  private move(dir: number): void {
    const n = this.games.length;
    if (n === 0) return;
    let next = this.selected;
    for (let step = 0; step < n; step++) {
      next = (next + dir + n) % n;
      if (this.games[next].enabled) {
        this.selected = next;
        break;
      }
    }
    this.refresh();
  }

  private refresh(): void {
    this.cards.forEach((c, i) => {
      const active = i === this.selected;
      const enabled = this.games[i].enabled;
      c.bg.setStrokeStyle(active ? 4 : 2, active ? 0xffeb3b : 0x333333);
      c.container.setScale(active && enabled ? 1.06 : 1);
    });
  }

  private confirm(): void {
    const game = this.games[this.selected];
    if (!game?.enabled) return;
    this.scene.start(game.entryKey);
  }
}
