import Phaser from "phaser";
import {
  EventKeys,
  SceneKeys,
  TextureKeys,
} from "@/games/parking/config/constants";
import {
  LOT_HEIGHT,
  LOT_WIDTH,
  LEVELS,
} from "@/games/parking/config/lot";
import { ParkingCar } from "@/games/parking/entities/ParkingCar";
import { ParkedCar } from "@/games/parking/entities/ParkedCar";
import { TargetSlot } from "@/games/parking/entities/TargetSlot";
import { ParkingScorer } from "@/games/parking/systems/ParkingScorer";
import { SoundManager } from "@/shared/audio/SoundManager";

const PARK_OVERLAP_THRESHOLD = 0.3;

export class GameScene extends Phaser.Scene {
  private player!: ParkingCar;
  private slot!: TargetSlot;
  private scorer!: ParkingScorer;
  private sound$!: SoundManager;
  private parkedGroup!: Phaser.Physics.Arcade.StaticGroup;
  private finished = false;
  private levelIndex = 0;

  constructor() {
    super(SceneKeys.Game);
  }

  init(data: { levelIndex?: number }): void {
    this.levelIndex = data.levelIndex ?? 0;
  }

  create(): void {
    this.finished = false;

    this.add
      .tileSprite(0, 0, LOT_WIDTH, LOT_HEIGHT, TextureKeys.Asphalt)
      .setOrigin(0, 0);

    this.drawLotMarkings();

    this.physics.world.setBounds(0, 0, LOT_WIDTH, LOT_HEIGHT);
    this.parkedGroup = this.physics.add.staticGroup();

    const level = LEVELS[this.levelIndex];

    this.slot = new TargetSlot(this, level.targetSlot);
    level.parkedCars.forEach((p) => new ParkedCar(this, this.parkedGroup, p));
    this.player = new ParkingCar(this, level.playerStart);
    this.sound$ = new SoundManager(this, { engine: "off" });
    this.scorer = new ParkingScorer(this, this.slot, () => this.player);

    this.physics.add.collider(
      this.player.sprite,
      this.parkedGroup,
      () => this.onCollision(),
      undefined,
      this,
    );

    this.scene.launch(SceneKeys.Hud, { levelIndex: this.levelIndex });
    this.events.emit(EventKeys.SpeedChanged, 0);
    this.scorer.reset();

    this.input.keyboard?.on("keydown-PERIOD", () => this.attemptPark());
    this.input.keyboard?.on("keydown-ESC", () => {
      this.scene.stop(SceneKeys.Hud);
      this.scene.start("hub:HubScene");
    });
  }

  override update(_time: number, delta: number): void {
    if (this.finished) return;
    const dt = delta / 1000;
    const kb = this.input.keyboard;
    if (!kb) return;

    const up = kb.checkDown(kb.addKey(Phaser.Input.Keyboard.KeyCodes.UP), 0);
    const down = kb.checkDown(kb.addKey(Phaser.Input.Keyboard.KeyCodes.DOWN), 0);
    const left = kb.checkDown(kb.addKey(Phaser.Input.Keyboard.KeyCodes.LEFT), 0);
    const right = kb.checkDown(kb.addKey(Phaser.Input.Keyboard.KeyCodes.RIGHT), 0);
    const space = kb.checkDown(kb.addKey(Phaser.Input.Keyboard.KeyCodes.SPACE), 0);

    let thrust: -1 | 0 | 1 = 0;
    if (up) thrust = 1;
    else if (down) thrust = -1;
    const brake = space ? 1 : 0;
    const steer = (right ? 1 : 0) - (left ? 1 : 0);

    this.player.update(dt, thrust, brake, steer, false);
    this.events.emit(EventKeys.SpeedChanged, this.player.speed);
    this.scorer.update();
  }

  private attemptPark(): void {
    if (this.finished) return;
    const overlap = this.slot.overlapRatio(
      this.player.position,
      this.player.angleDeg,
    );
    if (overlap < PARK_OVERLAP_THRESHOLD) {
      this.flashHint("önce slota gir");
      return;
    }
    this.finished = true;
    this.player.forceStop();
    this.events.emit(EventKeys.Parked);

    this.time.delayedCall(450, () => {
      const result = this.scorer.finalize();
      this.scene.stop(SceneKeys.Hud);
      this.scene.start(SceneKeys.GameOver, { ...result, levelIndex: this.levelIndex });
    });
  }

  private onCollision(): void {
    if (this.finished) return;
    if (!this.scorer.registerCollision()) return;
    this.cameras.main.shake(80, 0.005);
    this.sound$.crash();
  }

  private drawLotMarkings(): void {
    const g = this.add.graphics();
    g.lineStyle(2, 0xffffff, 0.35);
    g.strokeRect(20, 70, LOT_WIDTH - 40, LOT_HEIGHT - 140);
    g.lineBetween(20, LOT_HEIGHT / 2, LOT_WIDTH - 20, LOT_HEIGHT / 2);
  }

  private flashHint(text: string): void {
    const t = this.add
      .text(this.player.sprite.x, this.player.sprite.y - 50, text, {
        fontFamily: "system-ui, sans-serif",
        fontSize: "16px",
        color: "#ffeb3b",
        fontStyle: "bold",
        stroke: "#000",
        strokeThickness: 3,
      })
      .setOrigin(0.5);
    this.tweens.add({
      targets: t,
      y: t.y - 30,
      alpha: 0,
      duration: 700,
      ease: "Cubic.easeOut",
      onComplete: () => t.destroy(),
    });
  }
}
