import Phaser from "phaser";
import { GAME_HEIGHT, GAME_WIDTH, SceneKeys } from "@/games/overtake/config/constants";
import { CAR_CHOICES, CarChoice } from "@/games/overtake/config/cars";
import { HighScore } from "@/shared/storage/HighScore";

export class MenuScene extends Phaser.Scene {
  private selectedIndex = 0;
  private cards: Phaser.GameObjects.Container[] = [];

  constructor() {
    super(SceneKeys.Menu);
  }

  create(): void {
    this.cards = [];
    this.selectedIndex = 0;

    this.add
      .text(GAME_WIDTH / 2, 80, "MAKAS", {
        fontFamily: "system-ui, sans-serif",
        fontSize: "56px",
        color: "#ffeb3b",
        fontStyle: "bold",
      })
      .setOrigin(0.5);

    this.add
      .text(GAME_WIDTH / 2, 140, "Arabanı Seç", {
        fontFamily: "system-ui, sans-serif",
        fontSize: "20px",
        color: "#bdbdbd",
      })
      .setOrigin(0.5);

    const best = HighScore.load("overtake");
    if (best > 0) {
      this.add
        .text(GAME_WIDTH / 2, 170, `Rekor: ${best}`, {
          fontFamily: "system-ui, sans-serif",
          fontSize: "16px",
          color: "#a5d6a7",
        })
        .setOrigin(0.5);
    }

    CAR_CHOICES.forEach((choice, i) => {
      this.cards.push(this.buildCard(choice, i));
    });

    this.add
      .text(
        GAME_WIDTH / 2,
        GAME_HEIGHT - 60,
        "← →  seç    ENTER  başla",
        {
          fontFamily: "system-ui, sans-serif",
          fontSize: "16px",
          color: "#9e9e9e",
        },
      )
      .setOrigin(0.5);

    this.input.keyboard?.on("keydown-LEFT", () => this.move(-1));
    this.input.keyboard?.on("keydown-RIGHT", () => this.move(1));
    this.input.keyboard?.on("keydown-ENTER", () => this.confirm());
    this.input.keyboard?.on("keydown-SPACE", () => this.confirm());
    this.input.keyboard?.on("keydown-ESC", () => {
      this.scene.start("hub:HubScene");
    });

    this.refresh();
  }

  private buildCard(choice: CarChoice, i: number): Phaser.GameObjects.Container {
    const spacing = GAME_WIDTH / (CAR_CHOICES.length + 1);
    const x = spacing * (i + 1);
    const y = GAME_HEIGHT / 2;

    const container = this.add.container(x, y);
    const bg = this.add.rectangle(0, 0, 110, 200, 0x1f1f1f, 1);
    bg.setStrokeStyle(2, 0x333333);
    const sprite = this.add.image(0, -10, choice.textureKey);
    const label = this.add
      .text(0, 80, choice.label, {
        fontFamily: "system-ui, sans-serif",
        fontSize: "14px",
        color: "#eaeaea",
        align: "center",
        wordWrap: { width: 100 },
      })
      .setOrigin(0.5);

    container.add([bg, sprite, label]);
    container.setData("bg", bg);
    return container;
  }

  private move(dir: number): void {
    this.selectedIndex =
      (this.selectedIndex + dir + CAR_CHOICES.length) % CAR_CHOICES.length;
    this.refresh();
  }

  private refresh(): void {
    this.cards.forEach((card, i) => {
      const bg = card.getData("bg") as Phaser.GameObjects.Rectangle;
      const active = i === this.selectedIndex;
      bg.setStrokeStyle(active ? 4 : 2, active ? 0xffeb3b : 0x333333);
      card.setScale(active ? 1.08 : 1);
    });
  }

  private confirm(): void {
    const choice = CAR_CHOICES[this.selectedIndex];
    this.scene.start(SceneKeys.Intro, { choiceId: choice.id });
  }
}
