import Phaser from "phaser";
import { GAME_HEIGHT, GAME_WIDTH } from "@/shared/constants";
import { SceneKeys } from "@/games/parking/config/constants";
import { HighScore } from "@/shared/storage/HighScore";
import type { ParkResult } from "@/games/parking/systems/ParkingScorer";
import { LEVELS } from "@/games/parking/config/lot";

export interface GameOverData extends ParkResult {
  levelIndex: number;
}

export class GameOverScene extends Phaser.Scene {
  constructor() {
    super(SceneKeys.GameOver);
  }

  create(data: GameOverData): void {
    const isNewRecord = HighScore.save(`parking:level_${data.levelIndex}`, data.score);
    const best = HighScore.load(`parking:level_${data.levelIndex}`);

    this.add.rectangle(0, 0, GAME_WIDTH, GAME_HEIGHT, 0x000000, 0.7).setOrigin(0, 0);

    const isPass = data.stars > 0;
    const isLastLevel = data.levelIndex >= LEVELS.length - 1;
    const isVictory = isPass && isLastLevel;

    const titleText = isVictory ? "TEBRİKLER! OYUN BİTTİ" : `BÖLÜM ${data.levelIndex + 1} SONUCU`;
    const titleColor = isVictory ? "#4caf50" : "#ffeb3b";

    this.add
      .text(GAME_WIDTH / 2, GAME_HEIGHT / 2 - 160, titleText, {
        fontFamily: "system-ui, sans-serif",
        fontSize: "32px",
        color: titleColor,
        fontStyle: "bold",
      })
      .setOrigin(0.5);

    this.renderStars(data.stars);

    this.add
      .text(GAME_WIDTH / 2, GAME_HEIGHT / 2 - 20, `Skor: ${data.score}`, {
        fontFamily: "system-ui, sans-serif",
        fontSize: "30px",
        color: "#ffffff",
        fontStyle: "bold",
      })
      .setOrigin(0.5);

    this.add
      .text(
        GAME_WIDTH / 2,
        GAME_HEIGHT / 2 + 20,
        `Kalite ${data.quality} • Çarpma ${data.collisions}`,
        {
          fontFamily: "system-ui, sans-serif",
          fontSize: "16px",
          color: "#bdbdbd",
        },
      )
      .setOrigin(0.5);

    if (isNewRecord) {
      const banner = this.add
        .text(GAME_WIDTH / 2, GAME_HEIGHT / 2 + 60, "YENİ REKOR!", {
          fontFamily: "system-ui, sans-serif",
          fontSize: "20px",
          color: "#a5d6a7",
          fontStyle: "bold",
        })
        .setOrigin(0.5);
      this.tweens.add({
        targets: banner,
        scale: { from: 0.6, to: 1 },
        duration: 350,
        ease: "Back.easeOut",
      });
    } else if (best > 0) {
      this.add
        .text(GAME_WIDTH / 2, GAME_HEIGHT / 2 + 60, `En Yüksek: ${best}`, {
          fontFamily: "system-ui, sans-serif",
          fontSize: "16px",
          color: "#9e9e9e",
        })
        .setOrigin(0.5);
    }

    let mainActionText = "";

    if (isPass && !isLastLevel) {
      mainActionText = "ENTER  sonraki bölüm    ";
      this.input.keyboard?.once("keydown-ENTER", () => {
        this.scene.start(SceneKeys.Game, { levelIndex: data.levelIndex + 1 });
      });
      this.input.keyboard?.once("keydown-SPACE", () => {
        this.scene.start(SceneKeys.Game, { levelIndex: data.levelIndex + 1 });
      });
    } else if (!isPass) {
      mainActionText = "ENTER  tekrar dene    ";
      this.input.keyboard?.once("keydown-ENTER", () => {
        this.scene.start(SceneKeys.Game, { levelIndex: data.levelIndex });
      });
      this.input.keyboard?.once("keydown-SPACE", () => {
        this.scene.start(SceneKeys.Game, { levelIndex: data.levelIndex });
      });
    }

    this.add
      .text(
        GAME_WIDTH / 2,
        GAME_HEIGHT / 2 + 130,
        `${mainActionText}ESC  hub`,
        {
          fontFamily: "system-ui, sans-serif",
          fontSize: "16px",
          color: "#bdbdbd",
        },
      )
      .setOrigin(0.5);

    this.input.keyboard?.once("keydown-ESC", () => {
      this.scene.start("hub:HubScene");
    });
  }

  private renderStars(count: 0 | 1 | 2 | 3): void {
    const cy = GAME_HEIGHT / 2 - 90;
    const xs = [GAME_WIDTH / 2 - 50, GAME_WIDTH / 2, GAME_WIDTH / 2 + 50];
    for (let i = 0; i < 3; i++) {
      const filled = i < count;
      this.add
        .text(xs[i], cy, "★", {
          fontFamily: "system-ui, sans-serif",
          fontSize: "44px",
          color: filled ? "#ffeb3b" : "#3a3a3a",
        })
        .setOrigin(0.5);
    }
  }
}
