import Phaser from "phaser";
import { GAME_HEIGHT, GAME_WIDTH, TextureKeys } from "@/games/overtake/config/constants";
import { LANE_COUNT, LANE_WIDTH } from "@/games/overtake/config/lanes";

const STRIPE_HEIGHT = 40;
const STRIPE_GAP = 30;

export class Road {
  public scrollSpeed: number;
  private readonly scene: Phaser.Scene;
  private readonly stripes: Phaser.GameObjects.Image[] = [];
  private readonly asphalt: Phaser.GameObjects.Rectangle;

  constructor(scene: Phaser.Scene, initialSpeed = 0) {
    this.scene = scene;
    this.scrollSpeed = initialSpeed;

    this.asphalt = scene.add
      .rectangle(0, 0, GAME_WIDTH, GAME_HEIGHT, 0x2b2b2b)
      .setOrigin(0, 0);

    scene.add
      .rectangle(0, 0, 4, GAME_HEIGHT, 0xeeeeee, 0.9)
      .setOrigin(0, 0);
    scene.add
      .rectangle(GAME_WIDTH - 4, 0, 4, GAME_HEIGHT, 0xeeeeee, 0.9)
      .setOrigin(0, 0);

    this.spawnStripes();
  }

  private spawnStripes(): void {
    const totalPerLane = Math.ceil(GAME_HEIGHT / (STRIPE_HEIGHT + STRIPE_GAP)) + 2;
    for (let lane = 1; lane < LANE_COUNT; lane++) {
      const x = lane * LANE_WIDTH;
      for (let i = 0; i < totalPerLane; i++) {
        const stripe = this.scene.add.image(
          x,
          i * (STRIPE_HEIGHT + STRIPE_GAP),
          TextureKeys.RoadStripe,
        );
        stripe.setOrigin(0.5, 0);
        this.stripes.push(stripe);
      }
    }
  }

  update(deltaMs: number): void {
    const dy = this.scrollSpeed * (deltaMs / 1000);
    const cycle = STRIPE_HEIGHT + STRIPE_GAP;
    for (const s of this.stripes) {
      s.y += dy;
      if (s.y > GAME_HEIGHT) s.y -= cycle * Math.ceil(GAME_HEIGHT / cycle + 1);
    }
  }

  destroy(): void {
    this.stripes.forEach((s) => s.destroy());
    this.asphalt.destroy();
  }
}
