import Phaser from "phaser";
import { AudioKeys } from "./AudioKeys";
import type { EngineVoice, OneShotSfx } from "./EngineVoice";
import { SynthEngineVoice } from "./SynthEngineVoice";
import { SynthOneShots } from "./SynthOneShots";
import { SampledEngineVoice } from "./SampledEngineVoice";
import { SampledOneShots } from "./SampledOneShots";

export type EngineMode = "auto" | "off";

export interface SoundManagerOptions {
  /** Player speed at which engine voice reaches its top intensity. */
  maxSpeed?: number;
  /** "off" disables the continuous engine voice; one-shots still play. */
  engine?: EngineMode;
}

/**
 * Per-scene audio facade. Picks the best available backend at first user
 * input: if `AudioKeys.EngineLoop` is in the cache the sampled implementation
 * is used; otherwise it falls back to a Web Audio synth so the game still
 * has sound without assets. Pass `engine: "off"` for scenes that don't have
 * a continuous engine (e.g. parking lot).
 */
export class SoundManager {
  private readonly scene: Phaser.Scene;
  private readonly maxSpeed: number;
  private readonly mode: EngineMode;
  private ctx: AudioContext | null = null;
  private engine: EngineVoice | null = null;
  private oneShots: OneShotSfx | null = null;
  private prevSpeed = 0;
  private resumed = false;

  constructor(scene: Phaser.Scene, opts: SoundManagerOptions = {}) {
    this.scene = scene;
    this.maxSpeed = opts.maxSpeed ?? 100;
    this.mode = opts.engine ?? "auto";
    scene.events.once(Phaser.Scenes.Events.SHUTDOWN, () => this.dispose());
    scene.input.once("pointerdown", () => this.resume());
    scene.input.keyboard?.once("keydown", () => this.resume());
  }

  setSpeed(speed: number): void {
    if (this.engine) {
      const ratio = Phaser.Math.Clamp(speed / this.maxSpeed, 0, 1);
      this.engine.setSpeed(ratio);
      if (this.prevSpeed - speed > 30) this.engine.triggerBackfire();
    }
    this.prevSpeed = speed;
  }

  playGearShift(): void {
    this.oneShots?.gearShift();
  }

  crash(): void {
    this.oneShots?.crash();
  }

  private resume(): void {
    if (this.resumed) return;
    this.resumed = true;

    if (this.scene.cache.audio.exists(AudioKeys.EngineLoop)) {
      if (this.mode !== "off") this.engine = new SampledEngineVoice(this.scene);
      this.oneShots = new SampledOneShots(this.scene);
      return;
    }

    try {
      this.ctx = new AudioContext();
      if (this.mode !== "off") this.engine = new SynthEngineVoice(this.ctx);
      this.oneShots = new SynthOneShots(this.ctx);
    } catch {
      this.ctx = null;
    }
  }

  private dispose(): void {
    this.engine?.destroy();
    this.oneShots?.destroy();
    this.ctx?.close().catch(() => {});
    this.engine = null;
    this.oneShots = null;
    this.ctx = null;
  }
}
