import Phaser from "phaser";
import { TextureKeys } from "@/games/parking/config/constants";
import { CAR_HEIGHT, CAR_WIDTH, type SlotPos } from "@/games/parking/config/lot";

/**
 * Static obstacle car. Body is the car's axis-aligned rectangle; the layout
 * only uses 0° / 180° headings so the AABB matches the visual.
 */
export class ParkedCar {
  readonly sprite: Phaser.Physics.Arcade.Sprite;

  constructor(
    scene: Phaser.Scene,
    group: Phaser.Physics.Arcade.StaticGroup,
    pos: SlotPos,
  ) {
    this.sprite = scene.physics.add.staticSprite(pos.x, pos.y, TextureKeys.ParkedCar);
    const body = this.sprite.body as Phaser.Physics.Arcade.StaticBody;

    // Phaser'ın StaticBody hesaplamasındaki rotasyon-offset hatasını (kaymayı) önlemek için
    // önce rotasyonu 0 kabul edip kutuyu ortalıyoruz:
    this.sprite.setRotation(0);
    body.setSize(CAR_WIDTH - 6, CAR_HEIGHT - 6);
    body.setOffset(3, 3);
    body.updateFromGameObject();

    // Kutuyu hesapladıktan sonra görseli (arabayı) asıl yönüne çeviriyoruz:
    this.sprite.setRotation(Phaser.Math.DegToRad(pos.angle));

    group.add(this.sprite);
  }
}
