import Phaser from "phaser";
import { GAME_HEIGHT, GAME_WIDTH, SceneKeys } from "@/games/overtake/config/constants";
import { HighScore } from "@/shared/storage/HighScore";

interface GameOverData {
  readonly score: number;
}

export class GameOverScene extends Phaser.Scene {
  constructor() {
    super(SceneKeys.GameOver);
  }

  create(data: GameOverData): void {
    const isNewRecord = HighScore.save("overtake", data.score);
    const best = HighScore.load("overtake");

    this.add.rectangle(0, 0, GAME_WIDTH, GAME_HEIGHT, 0x000000, 0.7).setOrigin(0, 0);

    this.add
      .text(GAME_WIDTH / 2, GAME_HEIGHT / 2 - 120, "ÇARPIŞMA!", {
        fontFamily: "system-ui, sans-serif",
        fontSize: "48px",
        color: "#e53935",
        fontStyle: "bold",
      })
      .setOrigin(0.5);

    this.add
      .text(GAME_WIDTH / 2, GAME_HEIGHT / 2 - 40, `Geçtiğin Araba: ${data.score}`, {
        fontFamily: "system-ui, sans-serif",
        fontSize: "26px",
        color: "#ffeb3b",
      })
      .setOrigin(0.5);

    if (isNewRecord) {
      const banner = this.add
        .text(GAME_WIDTH / 2, GAME_HEIGHT / 2 + 10, "YENİ REKOR!", {
          fontFamily: "system-ui, sans-serif",
          fontSize: "22px",
          color: "#a5d6a7",
          fontStyle: "bold",
        })
        .setOrigin(0.5);
      this.tweens.add({
        targets: banner,
        scale: { from: 0.6, to: 1 },
        duration: 350,
        ease: "Back.easeOut",
      });
    } else {
      this.add
        .text(GAME_WIDTH / 2, GAME_HEIGHT / 2 + 10, `En Yüksek: ${best}`, {
          fontFamily: "system-ui, sans-serif",
          fontSize: "18px",
          color: "#9e9e9e",
        })
        .setOrigin(0.5);
    }

    this.add
      .text(
        GAME_WIDTH / 2,
        GAME_HEIGHT / 2 + 100,
        "ENTER  tekrar oyna    ESC  hub",
        {
          fontFamily: "system-ui, sans-serif",
          fontSize: "16px",
          color: "#bdbdbd",
        },
      )
      .setOrigin(0.5);

    this.input.keyboard?.once("keydown-ENTER", () => {
      this.scene.start(SceneKeys.Menu);
    });
    this.input.keyboard?.once("keydown-SPACE", () => {
      this.scene.start(SceneKeys.Menu);
    });
    this.input.keyboard?.once("keydown-ESC", () => {
      this.scene.start("hub:HubScene");
    });
  }
}
