import Phaser from "phaser";
import { TextureKeys } from "@/games/parking/config/constants";
import {
  CAR_HEIGHT,
  CAR_WIDTH,
  SLOT_HEIGHT,
  SLOT_WIDTH,
  type SlotPos,
} from "@/games/parking/config/lot";

/**
 * Visual + math for the target parking slot. Provides cheap alignment metrics
 * by comparing the car's center against the slot in the slot's local frame.
 * It's an approximation (treats both rectangles as AABB after rotating into
 * the slot's frame) — accurate enough for a casual scoring gauge.
 */
export class TargetSlot {
  readonly pos: SlotPos;
  readonly image: Phaser.GameObjects.Image;

  constructor(scene: Phaser.Scene, pos: SlotPos) {
    this.pos = pos;
    this.image = scene.add.image(pos.x, pos.y, TextureKeys.SlotMarker);
    this.image.setRotation(Phaser.Math.DegToRad(pos.angle));

    scene.tweens.add({
      targets: this.image,
      alpha: { from: 0.7, to: 1 },
      duration: 700,
      yoyo: true,
      repeat: -1,
      ease: "Sine.easeInOut",
    });
  }

  /** Approximate area-overlap ratio (0..1) of car footprint inside slot. */
  overlapRatio(carPos: { x: number; y: number }, _carAngleDeg: number): number {
    const a = -Phaser.Math.DegToRad(this.pos.angle);
    const dx = carPos.x - this.pos.x;
    const dy = carPos.y - this.pos.y;
    const localX = dx * Math.cos(a) - dy * Math.sin(a);
    const localY = dx * Math.sin(a) + dy * Math.cos(a);
    const overlapX = Math.max(
      0,
      SLOT_WIDTH / 2 + CAR_WIDTH / 2 - Math.abs(localX),
    );
    const overlapY = Math.max(
      0,
      SLOT_HEIGHT / 2 + CAR_HEIGHT / 2 - Math.abs(localY),
    );
    const carArea = CAR_WIDTH * CAR_HEIGHT;
    return Math.min(1, (overlapX * overlapY) / carArea);
  }

  /** Minimum heading delta in degrees, treating 180° as equivalent (front or back in slot). */
  angleDeltaDeg(carAngleDeg: number): number {
    let d = ((carAngleDeg - this.pos.angle) % 360 + 540) % 360 - 180;
    return Math.min(Math.abs(d), Math.abs(180 - Math.abs(d)));
  }
}
