import Phaser from "phaser";
import { EventKeys, GAME_HEIGHT, GAME_WIDTH, SceneKeys } from "@/games/overtake/config/constants";
import { CAR_CHOICES } from "@/games/overtake/config/cars";
import { Road } from "@/games/overtake/entities/Road";
import { PlayerCar } from "@/games/overtake/entities/PlayerCar";
import { TrafficCar } from "@/games/overtake/entities/TrafficCar";
import { GearSystem } from "@/games/overtake/systems/GearSystem";
import { TrafficSpawner } from "@/games/overtake/systems/TrafficSpawner";
import { MAX_SPEED } from "@/games/overtake/config/gears";
import { SoundManager } from "@/shared/audio/SoundManager";

interface GameData {
  readonly choiceId: string;
}

export class GameScene extends Phaser.Scene {
  private road!: Road;
  private player!: PlayerCar;
  private gears!: GearSystem;
  private spawner!: TrafficSpawner;
  private sound$!: SoundManager;
  private traffic!: Phaser.Physics.Arcade.Group;
  private score = 0;
  private overtakenIds = new Set<number>();

  constructor() {
    super(SceneKeys.Game);
  }

  create(data: GameData): void {
    const choice = CAR_CHOICES.find((c) => c.id === data.choiceId) ?? CAR_CHOICES[0];

    this.road = new Road(this, 0);
    this.gears = new GearSystem(this, choice);
    this.sound$ = new SoundManager(this, { maxSpeed: MAX_SPEED });
    this.player = new PlayerCar(this, choice);
    this.traffic = this.physics.add.group();
    this.spawner = new TrafficSpawner(this, this.traffic);

    this.scene.launch(SceneKeys.Hud);

    this.events.on(EventKeys.SpeedChanged, (s: number) => this.sound$.setSpeed(s));
    this.events.on(EventKeys.GearChanged, () => this.sound$.playGearShift());

    this.input.keyboard?.on("keydown-LEFT", () => this.player.changeLane(-1));
    this.input.keyboard?.on("keydown-RIGHT", () => this.player.changeLane(1));
    this.input.keyboard?.on("keydown-X", () => this.gears.shiftUp());
    this.input.keyboard?.on("keydown-Z", () => this.gears.shiftDown());

    this.physics.add.overlap(
      this.player.sprite,
      this.traffic,
      () => this.handleCrash(),
      undefined,
      this,
    );

    this.score = 0;
    this.overtakenIds.clear();
    this.events.emit(EventKeys.ScoreChanged, this.score);
    this.gears.start(80, 1);
  }

  override update(_time: number, delta: number): void {
    const dt = delta / 1000;
    const upPressed = this.input.keyboard?.checkDown(
      this.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.UP),
      0,
    );
    const downPressed = this.input.keyboard?.checkDown(
      this.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.DOWN),
      0,
    );

    this.gears.update(dt, !!upPressed, !!downPressed);
    const speed = this.gears.speed;

    this.road.scrollSpeed = speed;
    this.road.update(delta);
    this.player.update(dt);
    this.spawner.update(dt, speed);

    const toDestroy: TrafficCar[] = [];
    this.traffic.children.iterate((obj) => {
      if (!obj) return true;
      const car = obj as Phaser.Physics.Arcade.Sprite;
      const ref = car.getData("ref") as TrafficCar | undefined;
      if (!ref) return true;
      ref.update(dt, speed);

      if (
        !this.overtakenIds.has(ref.id) &&
        car.y > this.player.sprite.y + 40
      ) {
        this.overtakenIds.add(ref.id);
        this.registerOvertake(ref);
      }

      if (car.y > GAME_HEIGHT + 120) {
        toDestroy.push(ref);
      }
      return true;
    });
    toDestroy.forEach((c) => c.destroy());
  }

  private registerOvertake(overtaken: TrafficCar): void {
    const isMakas = this.isCloseSqueeze(overtaken);
    const basePoints = isMakas ? 3 : 1;
    const multiplier = this.gears.isTopGear ? 2 : 1;
    this.score += basePoints * multiplier;
    this.events.emit(EventKeys.ScoreChanged, this.score);
    this.events.emit(EventKeys.Overtake);

    if (isMakas) {
      this.events.emit(EventKeys.Makas);
      this.showMakasPopup(multiplier);
    }
  }

  private isCloseSqueeze(overtaken: TrafficCar): boolean {
    const playerLane = this.player.currentLane;
    const playerY = this.player.sprite.y;
    let near = false;
    this.traffic.children.iterate((obj) => {
      if (!obj || near) return true;
      const car = obj as Phaser.Physics.Arcade.Sprite;
      const ref = car.getData("ref") as TrafficCar | undefined;
      if (!ref || ref.id === overtaken.id) return true;
      const laneDiff = Math.abs(ref.lane - playerLane);
      const verticalDist = Math.abs(car.y - playerY);
      if (laneDiff <= 1 && verticalDist < 110) near = true;
      return true;
    });
    return near;
  }

  private showMakasPopup(multiplier: number): void {
    const text = multiplier > 1 ? "MAKAS! x2" : "MAKAS!";
    const popup = this.add
      .text(this.player.sprite.x, this.player.sprite.y - 40, text, {
        fontFamily: "system-ui, sans-serif",
        fontSize: "22px",
        color: "#ffeb3b",
        fontStyle: "bold",
        stroke: "#000",
        strokeThickness: 4,
      })
      .setOrigin(0.5);
    this.tweens.add({
      targets: popup,
      y: popup.y - 60,
      alpha: 0,
      duration: 700,
      ease: "Cubic.easeOut",
      onComplete: () => popup.destroy(),
    });
  }

  private handleCrash(): void {
    this.sound$.crash();
    this.scene.stop(SceneKeys.Hud);
    this.scene.start(SceneKeys.GameOver, { score: this.score });
  }

  get gearSystem(): GearSystem {
    return this.gears;
  }

  get sounds(): SoundManager {
    return this.sound$;
  }

  get bounds(): { width: number; height: number } {
    return { width: GAME_WIDTH, height: GAME_HEIGHT };
  }
}
