import Phaser from "phaser";
import type { OneShotSfx } from "./EngineVoice";
import { AudioKeys } from "./AudioKeys";

export class SampledOneShots implements OneShotSfx {
  constructor(private readonly scene: Phaser.Scene) {}

  gearShift(): void {
    if (this.scene.cache.audio.exists(AudioKeys.GearShift)) {
      this.scene.sound.play(AudioKeys.GearShift, { volume: 0.5 });
    }
  }

  crash(): void {
    if (this.scene.cache.audio.exists(AudioKeys.Crash)) {
      this.scene.sound.play(AudioKeys.Crash, { volume: 0.7 });
    }
  }

  destroy(): void {
    /* nothing to release; scene handles sound disposal */
  }
}
