import type Phaser from "phaser";
import { overtakeGame } from "@/games/overtake";
import { parkingGame } from "@/games/parking";

export interface GameDefinition {
  /** Unique slug used for HighScore keys, scene/texture namespace, etc. */
  readonly id: string;
  /** Human-readable name displayed on the hub card. */
  readonly label: string;
  /** Single-line tag shown under the label on the hub card. */
  readonly tagline: string;
  /** All scene classes this game contributes; statically registered in main.ts. */
  readonly scenes: ReadonlyArray<new () => Phaser.Scene>;
  /** Scene the hub starts when this game is selected (e.g. game's Boot). */
  readonly entryKey: string;
  /** Set false to render a disabled placeholder card (e.g. WIP games). */
  readonly enabled: boolean;
}

export const gameRegistry: ReadonlyArray<GameDefinition> = [
  parkingGame,
  overtakeGame,
];
