import Phaser from "phaser";
import { GAME_HEIGHT, GAME_WIDTH } from "@/shared/constants";
import { EventKeys, SceneKeys } from "@/games/parking/config/constants";
import { LEVELS } from "@/games/parking/config/lot";

const GAUGE_X = 20;
const GAUGE_Y = GAME_HEIGHT - 36;
const GAUGE_W = GAME_WIDTH - 40;
const GAUGE_H = 14;

export class HudScene extends Phaser.Scene {
  private speedText!: Phaser.GameObjects.Text;
  private collisionsText!: Phaser.GameObjects.Text;
  private gauge!: Phaser.GameObjects.Graphics;
  private hint!: Phaser.GameObjects.Text;
  private levelIndex = 0;

  constructor() {
    super(SceneKeys.Hud);
  }

  init(data: { levelIndex?: number }): void {
    this.levelIndex = data.levelIndex ?? 0;
  }

  create(): void {
    const game = this.scene.get(SceneKeys.Game);

    this.add.rectangle(0, 0, GAME_WIDTH, 50, 0x000000, 0.55).setOrigin(0, 0);

    this.add
      .text(20, 25, `BÖLÜM ${this.levelIndex + 1} / ${LEVELS.length}`, {
        fontFamily: "system-ui, sans-serif",
        fontSize: "16px",
        color: "#ffeb3b",
        fontStyle: "bold",
      })
      .setOrigin(0, 0.5);

    this.speedText = this.add
      .text(GAME_WIDTH / 2, 25, "0 km/s", {
        fontFamily: "system-ui, sans-serif",
        fontSize: "20px",
        color: "#ffffff",
        fontStyle: "bold",
      })
      .setOrigin(0.5);

    this.collisionsText = this.add
      .text(GAME_WIDTH - 20, 25, "Çarpma: 0", {
        fontFamily: "system-ui, sans-serif",
        fontSize: "14px",
        color: "#ef9a9a",
      })
      .setOrigin(1, 0.5);

    this.gauge = this.add.graphics();
    this.drawGauge(0);

    this.hint = this.add
      .text(GAME_WIDTH / 2, GAUGE_Y - 18, "Yön tuşları: Hareket   . (Nokta): Park et", {
        fontFamily: "system-ui, sans-serif",
        fontSize: "12px",
        color: "#9e9e9e",
      })
      .setOrigin(0.5);

    game.events.on(EventKeys.SpeedChanged, (s: number) => {
      this.speedText.setText(`${Math.round(Math.abs(s))} km/s`);
    });
    game.events.on(EventKeys.QualityChanged, (q: number) => {
      this.drawGauge(q);
      this.updateHint(q);
    });
    game.events.on(EventKeys.CollisionsChanged, (c: number) => {
      this.collisionsText.setText(`Çarpma: ${c}`);
    });

    this.events.once(Phaser.Scenes.Events.SHUTDOWN, () => {
      game.events.off(EventKeys.SpeedChanged);
      game.events.off(EventKeys.QualityChanged);
      game.events.off(EventKeys.CollisionsChanged);
    });
  }

  private drawGauge(quality: number): void {
    const ratio = Phaser.Math.Clamp(quality / 100, 0, 1);
    this.gauge.clear();
    this.gauge.fillStyle(0x222222, 0.85);
    this.gauge.fillRoundedRect(GAUGE_X, GAUGE_Y, GAUGE_W, GAUGE_H, 5);
    this.gauge.fillStyle(this.colorFor(ratio), 1);
    this.gauge.fillRoundedRect(GAUGE_X, GAUGE_Y, GAUGE_W * ratio, GAUGE_H, 5);
  }

  private colorFor(ratio: number): number {
    if (ratio >= 0.75) return 0x4caf50;
    if (ratio >= 0.4) return 0xfdd835;
    return 0xe53935;
  }

  private updateHint(quality: number): void {
    if (quality >= 75) {
      this.hint.setText(". (Nokta) ile park et");
      this.hint.setColor("#a5d6a7");
    } else {
      this.hint.setText("Yön tuşları: Hareket   Boşluk (Space): Fren   . (Nokta): Park et");
      this.hint.setColor("#9e9e9e");
    }
  }
}
