import Phaser from "phaser";
import { EventKeys } from "@/games/parking/config/constants";
import type { ParkingCar } from "@/games/parking/entities/ParkingCar";
import type { TargetSlot } from "@/games/parking/entities/TargetSlot";

export interface ParkResult {
  score: number;
  quality: number;
  collisions: number;
  stars: 0 | 1 | 2 | 3;
}

const COLLISION_PENALTY = 5;
const ANGLE_TOLERANCE_DEG = 5;
const ANGLE_PENALTY_PER_DEG = 1.5;
const COLLISION_COOLDOWN_MS = 350;

/**
 * Continuous "park quality" gauge. Emits a 0..100 number every frame so the
 * HUD bar reflects what the car is doing live. The final score subtracts a
 * collision penalty, so the player sees their target moving as they bump
 * into things.
 */
export class ParkingScorer {
  private collisions = 0;
  private lastQuality = 0;
  private lastCollisionAt = -Infinity;

  constructor(
    private readonly scene: Phaser.Scene,
    private readonly slot: TargetSlot,
    private readonly getCar: () => ParkingCar,
  ) {}

  reset(): void {
    this.collisions = 0;
    this.lastQuality = 0;
    this.lastCollisionAt = -Infinity;
    this.scene.events.emit(EventKeys.CollisionsChanged, 0);
    this.scene.events.emit(EventKeys.QualityChanged, 0);
  }

  /** Returns true only for the *first* contact of a bump (cooldown-deduped). */
  registerCollision(): boolean {
    const now = this.scene.time.now;
    if (now - this.lastCollisionAt < COLLISION_COOLDOWN_MS) return false;
    this.lastCollisionAt = now;
    this.collisions += 1;
    this.scene.events.emit(EventKeys.CollisionsChanged, this.collisions);
    return true;
  }

  /** Call every frame to refresh the live quality gauge. */
  update(): void {
    const q = this.computeQuality();
    if (Math.abs(q - this.lastQuality) >= 0.5) {
      this.lastQuality = q;
      this.scene.events.emit(EventKeys.QualityChanged, q);
    }
  }

  computeQuality(): number {
    const car = this.getCar();
    const overlap = this.slot.overlapRatio(car.position, car.angleDeg);
    const angleDelta = this.slot.angleDeltaDeg(car.angleDeg);
    const speedPenalty = Phaser.Math.Clamp(Math.abs(car.speed) * 0.5, 0, 40);
    const anglePenalty =
      Math.max(0, angleDelta - ANGLE_TOLERANCE_DEG) * ANGLE_PENALTY_PER_DEG;
    return Math.max(0, 100 * overlap - anglePenalty - speedPenalty);
  }

  finalize(): ParkResult {
    const quality = this.computeQuality();
    const score = Math.max(
      0,
      Math.round(quality - COLLISION_PENALTY * this.collisions),
    );
    const stars: 0 | 1 | 2 | 3 =
      score >= 80 ? 3 : score >= 50 ? 2 : score >= 20 ? 1 : 0;
    return {
      score,
      quality: Math.round(quality),
      collisions: this.collisions,
      stars,
    };
  }
}
