import Phaser from "phaser";
import { GAME_HEIGHT, GAME_WIDTH, SceneKeys } from "@/games/overtake/config/constants";
import { Road } from "@/games/overtake/entities/Road";
import { CAR_CHOICES } from "@/games/overtake/config/cars";

interface CountdownData {
  readonly choiceId: string;
}

export class CountdownScene extends Phaser.Scene {
  private road!: Road;

  constructor() {
    super(SceneKeys.Countdown);
  }

  create(data: CountdownData): void {
    const choice = CAR_CHOICES.find((c) => c.id === data.choiceId) ?? CAR_CHOICES[0];
    this.road = new Road(this, 480);

    this.add.image(GAME_WIDTH / 2, GAME_HEIGHT - 160, choice.textureKey);

    const text = this.add
      .text(GAME_WIDTH / 2, GAME_HEIGHT / 2, "3", {
        fontFamily: "system-ui, sans-serif",
        fontSize: "160px",
        color: "#ffeb3b",
        fontStyle: "bold",
      })
      .setOrigin(0.5);

    const sequence: Array<string | null> = ["3", "2", "1", "BAŞLA!", null];
    let step = 0;

    const tick = (): void => {
      const value = sequence[step++];
      if (value === null) {
        this.scene.start(SceneKeys.Game, { choiceId: choice.id });
        return;
      }
      text.setText(value);
      text.setScale(1.4);
      this.tweens.add({
        targets: text,
        scale: 1,
        duration: 700,
        ease: "Cubic.easeOut",
      });
      this.time.delayedCall(900, tick);
    };

    text.setText("");
    this.time.delayedCall(200, tick);
  }

  override update(_time: number, delta: number): void {
    this.road.update(delta);
  }
}
