import Phaser from "phaser";
import { TRAFFIC_TEXTURES } from "@/games/overtake/config/cars";
import { LANE_COUNT } from "@/games/overtake/config/lanes";
import { TrafficCar } from "@/games/overtake/entities/TrafficCar";

const SPAWN_INTERVAL_EASY: [number, number] = [1.0, 1.8];
const SPAWN_INTERVAL_HARD: [number, number] = [0.35, 0.8];
const TRAFFIC_SPEED_EASY: [number, number] = [60, 180];
const TRAFFIC_SPEED_HARD: [number, number] = [120, 280];
const RAMP_DURATION = 90;
const SPAWN_Y = -120;
const MIN_GAP_BETWEEN_CARS = 180;

export class TrafficSpawner {
  private readonly scene: Phaser.Scene;
  private readonly group: Phaser.Physics.Arcade.Group;
  private timer = 0;
  private elapsed = 0;
  private nextSpawnIn: number;

  constructor(scene: Phaser.Scene, group: Phaser.Physics.Arcade.Group) {
    this.scene = scene;
    this.group = group;
    this.nextSpawnIn = SPAWN_INTERVAL_EASY[0];
  }

  update(dt: number, _playerSpeed: number): void {
    this.elapsed += dt;
    this.timer += dt;
    if (this.timer < this.nextSpawnIn) return;
    this.timer = 0;
    const intensity = Phaser.Math.Clamp(this.elapsed / RAMP_DURATION, 0, 1);
    const [iMin, iMax] = this.lerpRange(SPAWN_INTERVAL_EASY, SPAWN_INTERVAL_HARD, intensity);
    this.nextSpawnIn = Phaser.Math.FloatBetween(iMin, iMax);
    this.trySpawn(intensity);
  }

  /** Difficulty (0..1) so HUD or other systems can reflect it. */
  get intensity(): number {
    return Phaser.Math.Clamp(this.elapsed / RAMP_DURATION, 0, 1);
  }

  private trySpawn(intensity: number): void {
    const lane = this.pickAvailableLane();
    if (lane === null) return;

    const texture = Phaser.Utils.Array.GetRandom([...TRAFFIC_TEXTURES]) as string;
    const [sMin, sMax] = this.lerpRange(TRAFFIC_SPEED_EASY, TRAFFIC_SPEED_HARD, intensity);
    const speed = Phaser.Math.FloatBetween(sMin, sMax);
    new TrafficCar(this.scene, this.group, lane, texture, speed, SPAWN_Y);
  }

  private lerpRange(
    a: readonly [number, number],
    b: readonly [number, number],
    t: number,
  ): [number, number] {
    return [Phaser.Math.Linear(a[0], b[0], t), Phaser.Math.Linear(a[1], b[1], t)];
  }

  /**
   * Picks a lane that respects two invariants regardless of difficulty:
   * 1. Not all 4 lanes can be blocked near the top simultaneously - at least
   *    one lane must remain open so the player can always overtake.
   * 2. The chosen lane must have enough vertical gap from the last spawned car
   *    so the player can fit between them.
   */
  private pickAvailableLane(): number | null {
    const occupiedNearTop = new Set<number>();
    const lastYPerLane = new Map<number, number>();

    this.group.children.iterate((obj) => {
      if (!obj) return true;
      const sprite = obj as Phaser.Physics.Arcade.Sprite;
      const ref = sprite.getData("ref") as TrafficCar | undefined;
      if (!ref) return true;
      if (sprite.y < 200) occupiedNearTop.add(ref.lane);
      const prev = lastYPerLane.get(ref.lane);
      if (prev === undefined || sprite.y < prev) {
        lastYPerLane.set(ref.lane, sprite.y);
      }
      return true;
    });

    const candidates: number[] = [];
    for (let lane = 0; lane < LANE_COUNT; lane++) {
      const lastY = lastYPerLane.get(lane);
      const hasGap = lastY === undefined || lastY > SPAWN_Y + MIN_GAP_BETWEEN_CARS;
      if (hasGap) candidates.push(lane);
    }

    if (occupiedNearTop.size >= LANE_COUNT - 1) {
      const free = candidates.filter((l) => !occupiedNearTop.has(l));
      return free.length ? Phaser.Utils.Array.GetRandom(free) : null;
    }

    if (!candidates.length) return null;
    return Phaser.Utils.Array.GetRandom(candidates);
  }
}
