import Phaser from "phaser";
import { SceneKeys, TextureKeys } from "@/games/parking/config/constants";
import { CAR_HEIGHT, CAR_WIDTH } from "@/games/parking/config/lot";

export class BootScene extends Phaser.Scene {
  constructor() {
    super(SceneKeys.Boot);
  }

  preload(): void {
    this.generateCar(TextureKeys.PlayerCar, 0xfdd835);
    this.generateCar(TextureKeys.ParkedCar, 0x546e7a);
    this.generateAsphalt();
    this.generateSlotMarker();
  }

  create(): void {
    this.scene.start(SceneKeys.Game);
  }

  private generateCar(key: string, color: number): void {
    if (this.textures.exists(key)) return;
    const g = this.add.graphics();
    g.fillStyle(0x111111, 1);
    g.fillRoundedRect(0, 0, CAR_WIDTH, CAR_HEIGHT, 6);
    g.fillStyle(color, 1);
    g.fillRoundedRect(3, 5, CAR_WIDTH - 6, CAR_HEIGHT - 10, 4);
    g.fillStyle(0x0d0d0d, 1);
    g.fillRect(8, 16, CAR_WIDTH - 16, 14);
    g.fillRect(8, CAR_HEIGHT - 30, CAR_WIDTH - 16, 14);
    g.fillStyle(0xfff59d, 1);
    g.fillRect(5, 2, 6, 4);
    g.fillRect(CAR_WIDTH - 11, 2, 6, 4);
    g.generateTexture(key, CAR_WIDTH, CAR_HEIGHT);
    g.destroy();
  }

  private generateAsphalt(): void {
    if (this.textures.exists(TextureKeys.Asphalt)) return;
    const g = this.add.graphics();
    g.fillStyle(0x303030, 1);
    g.fillRect(0, 0, 64, 64);
    g.fillStyle(0x363636, 1);
    g.fillRect(2, 2, 30, 30);
    g.fillRect(34, 34, 28, 28);
    g.generateTexture(TextureKeys.Asphalt, 64, 64);
    g.destroy();
  }

  private generateSlotMarker(): void {
    if (this.textures.exists(TextureKeys.SlotMarker)) return;
    const g = this.add.graphics();
    const w = 70;
    const h = 120;
    g.fillStyle(0xffeb3b, 0.18);
    g.fillRect(0, 0, w, h);
    g.lineStyle(4, 0xffeb3b, 1);
    g.strokeRect(2, 2, w - 4, h - 4);
    g.lineStyle(2, 0xffeb3b, 0.55);
    for (let i = -2; i < 10; i++) {
      g.beginPath();
      g.moveTo(2, i * 14);
      g.lineTo(w - 2, i * 14 + 22);
      g.strokePath();
    }
    g.generateTexture(TextureKeys.SlotMarker, w, h);
    g.destroy();
  }
}
